from autogen_agentchat.agents import AssistantAgentfrom mcp_config import McpConfigclass AgentFactory:    def __init__(self, model_client):        self.model_client = model_client    def create_database_agent(self, system_message):        database_agent = AssistantAgent(            name="DatabaseAgent",            model_client=self.model_client,            workbench=McpConfig.get_mysql_workbench(),            system_message=system_message,        )        return database_agent    def create_api_agent(self, system_message):        rest_api_workbench = McpConfig.get_rest_api_workbench()        fs_workbench = McpConfig.get_fs_workbench()        api_agent = AssistantAgent(            name="APIAgent",            model_client=self.model_client,            workbench=[rest_api_workbench, fs_workbench],            system_message=system_message,        )        return api_agent    def create_excel_agent(self, system_message):        excel_agent = AssistantAgent(            name="ExcelAgent",            model_client=self.model_client,            workbench=McpConfig.get_excel_workbench(),            system_message=system_message,        )        return excel_agent